// assets/js/worker-csv.js

function normalizeNewlines(s) {
  return s.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
}

function decodeArrayBuffer(buf, encSel) {
  const enc = encSel === 'utf-8-bom' ? 'utf-8' : encSel;
  let text = '';
  try {
    text = new TextDecoder(enc, { fatal: false }).decode(buf);
  } catch (e) {
    text = new TextDecoder('utf-8', { fatal: false }).decode(buf);
  }
  if (text.startsWith('\uFEFF')) text = text.slice(1);
  return text.replace(/\u0000/g, '');
}

function parseCSV(text, delimiterChar) {
  const delim = delimiterChar === 'tab' ? '\t' : delimiterChar;
  const s = normalizeNewlines(text);

  const rows = [];
  let i = 0,
    field = '',
    row = [],
    inQuotes = false;

  while (i < s.length) {
    const ch = s[i];

    if (inQuotes) {
      if (ch === '"') {
        if (s[i + 1] === '"') {
          field += '"';
          i += 2;
          continue;
        }
        inQuotes = false;
        i++;
        continue;
      } else {
        field += ch;
        i++;
        continue;
      }
    } else {
      if (ch === '"') {
        inQuotes = true;
        i++;
        continue;
      }
      if (ch === delim) {
        row.push(field);
        field = '';
        i++;
        continue;
      }
      if (ch === '\n') {
        row.push(field);
        rows.push(row);
        field = '';
        row = [];
        i++;
        continue;
      }
      field += ch;
      i++;
      continue;
    }
  }
  row.push(field);
  rows.push(row);

  while (
    rows.length &&
    rows[rows.length - 1].length === 1 &&
    rows[rows.length - 1][0].trim() === ''
  ) {
    rows.pop();
  }
  return rows;
}

function safeKey(s, idx) {
  const t = (s ?? '').trim();
  if (!t) return `col${idx + 1}`;
  return t.replace(/\s+/g, '_').replace(/[^\w\-]/g, '_');
}

function csvToJson(text, delimiter, hasHeader) {
  const rows = parseCSV(text, delimiter);
  if (!rows.length) return { json: [], headers: [], rowsCount: 0 };

  let headers = [];
  let start = 0;

  if (hasHeader) {
    headers = rows[0].map((h, i) => safeKey(h, i));
    start = 1;
  } else {
    const maxCols = Math.max(...rows.map((r) => r.length));
    headers = Array.from({ length: maxCols }, (_, i) => `col${i + 1}`);
  }

  const json = rows.slice(start).map((r) => {
    const o = {};
    for (let i = 0; i < headers.length; i++) {
      o[headers[i]] = r[i] ?? '';
    }
    return o;
  });

  return { json, headers, rowsCount: rows.length };
}

self.addEventListener('message', async (e) => {
  const { fileBuffer, textData, isTextMode, fileEncoding, delimiter, hasHeader } = e.data;
  try {
    let text = '';
    if (isTextMode) {
      text = textData;
    } else {
      text = decodeArrayBuffer(fileBuffer, fileEncoding);
    }

    const { json, headers, rowsCount } = csvToJson(text, delimiter, hasHeader);

    // Use JSON.stringify outside the main thread memory allocation for the big string if possible
    // Although returning raw JSON object to main thread takes structured clone overhead.
    // Typically it is faster to stringify in the worker to not block the main thread.
    const jsonText = JSON.stringify(json, null, 2);

    self.postMessage({ success: true, json, jsonText, headers, rowsCount });
  } catch (err) {
    self.postMessage({ success: false, error: err.message });
  }
});

const fs = require('fs');
const path = require('path');

function processFile(filePath) {
  let content = fs.readFileSync(filePath, 'utf8');

  // Check if we already injected breadcrumbs
  if (content.includes('"@type": "BreadcrumbList"')) {
    return;
  }

  // Extract title
  const titleMatch = content.match(/<title>([\s\S]*?)<\/title>/);
  const title = titleMatch ? titleMatch[1].trim() : 'ConvertFileBox';

  // Extract canonical URL
  const canonicalMatch = content.match(/<link\s+rel="canonical"\s+href="([^"]+)"\s*\/>/i);
  let canonicalUrl = canonicalMatch ? canonicalMatch[1] : '';

  if (!canonicalUrl) {
    return;
  }

  let urlObj;
  try {
    urlObj = new URL(canonicalUrl);
  } catch (e) {
    return;
  }

  const pathname = urlObj.pathname;
  const segments = pathname.split('/').filter(Boolean);

  // Build BreadcrumbList
  let breadcrumbs = [];
  if (segments.length >= 1) {
    const lang = segments[0]; // en-us or ja-jp
    breadcrumbs.push({
      '@type': 'ListItem',
      position: 1,
      name: 'Home',
      item: `https://www.convertfilebox.net/${lang}/`,
    });

    if (segments.length >= 2 && segments[1] === 'tools') {
      breadcrumbs.push({
        '@type': 'ListItem',
        position: 2,
        name: lang === 'ja-jp' ? 'ツール一覧' : 'Tools',
        item: `https://www.convertfilebox.net/${lang}/tools/`,
      });

      if (segments.length >= 3) {
        breadcrumbs.push({
          '@type': 'ListItem',
          position: 3,
          name: title,
          item: canonicalUrl,
        });
      }
    } else if (segments.length >= 2 && segments[1] === 'about') {
      breadcrumbs.push({
        '@type': 'ListItem',
        position: 2,
        name: lang === 'ja-jp' ? 'このサイトについて' : 'About',
        item: canonicalUrl,
      });
    } else if (segments.length >= 2 && segments[1] === 'privacy') {
      breadcrumbs.push({
        '@type': 'ListItem',
        position: 2,
        name: lang === 'ja-jp' ? 'プライバシーポリシー' : 'Privacy Policy',
        item: canonicalUrl,
      });
    }
  }

  const breadcrumbData = {
    '@context': 'https://schema.org',
    '@type': 'BreadcrumbList',
    itemListElement: breadcrumbs,
  };

  // Build FAQPage
  const faqRegex =
    /<h4[^>]*>([QＱ][.．]?\s*)(.*?)<\/h4>\s*<p[^>]*>([AＡ][.．]?\s*)([\s\S]*?)<\/p>/gi;
  let match;
  let faqContent = [];

  while ((match = faqRegex.exec(content)) !== null) {
    const q = match[2].trim();
    const a = match[4]
      .replace(/<[^>]+>/g, '')
      .trim()
      .replace(/\s+/g, ' ');
    faqContent.push({
      '@type': 'Question',
      name: q,
      acceptedAnswer: {
        '@type': 'Answer',
        text: a,
      },
    });
  }

  let structuredDataArr = [];
  if (breadcrumbs.length > 0) {
    structuredDataArr.push(breadcrumbData);
  }
  if (faqContent.length > 0) {
    structuredDataArr.push({
      '@context': 'https://schema.org',
      '@type': 'FAQPage',
      mainEntity: faqContent,
    });
  }

  // Inject script
  const scriptContent = structuredDataArr
    .map(
      (d) =>
        `    <script type="application/ld+json">\n${JSON.stringify(d, null, 2)
          .split('\n')
          .map((l, i) => (i === 0 ? l : '      ' + l))
          .join('\n')}\n    </script>`,
    )
    .join('\n');

  if (structuredDataArr.length > 0) {
    // Inject just before </head>
    content = content.replace(/(<\/head>)/i, `${scriptContent}\n  $1`);
    fs.writeFileSync(filePath, content, 'utf8');
    console.log(`Injected structured data into ${filePath}`);
  }
}

function traverse(dir) {
  if (!fs.existsSync(dir)) return;
  const files = fs.readdirSync(dir);
  for (const file of files) {
    const fullPath = path.join(dir, file);
    if (fs.statSync(fullPath).isDirectory()) {
      const ignoredDirs = [
        'en-us_broken',
        'ja-jp_broken',
        'node_modules',
        '.git',
        '.github',
        'assets',
        'scripts',
        'tests',
        'docs',
        '.husky',
      ];
      if (!ignoredDirs.includes(file)) {
        traverse(fullPath);
      }
    } else if (fullPath.endsWith('.html')) {
      processFile(fullPath);
    }
  }
}

console.log('Starting traversal...');
traverse(path.join(__dirname, '..', 'en-us'));
traverse(path.join(__dirname, '..', 'ja-jp'));

// Also root index.html
const rootIndex = path.join(__dirname, '..', 'index.html');
if (fs.existsSync(rootIndex)) {
  console.log('Processing root index');
  processFile(rootIndex);
}

const fs = require('fs');
const path = require('path');

const csp = `
    <!-- Strict Content Security Policy -->
    <meta http-equiv="Content-Security-Policy" content="default-src 'self'; script-src 'self' 'unsafe-inline' https://pagead2.googlesyndication.com https://www.googletagmanager.com; style-src 'self' 'unsafe-inline' https://fonts.googleapis.com; font-src 'self' https://fonts.gstatic.com; img-src 'self' data: https://pagead2.googlesyndication.com https://www.google.com; frame-src https://googleads.g.doubleclick.net https://www.google.com;" />
`;

function processFile(filePath) {
  let content = fs.readFileSync(filePath, 'utf8');
  if (content.includes('Content-Security-Policy')) return; // Already processed

  // Extract title
  const titleMatch = content.match(/<title>([\s\S]*?)<\/title>/);
  const title = titleMatch ? titleMatch[1].trim() : 'ConvertFileBox';

  // Extract description
  const descMatch = content.match(/<meta\s+name="description"\s+content="([\s\S]*?)"\s*\/>/i);
  let description = descMatch ? descMatch[1].trim() : '';

  // Extract canonical URL
  const canonicalMatch = content.match(/<link\s+rel="canonical"\s+href="([^"]+)"\s*\/>/i);
  let canonicalUrl = canonicalMatch ? canonicalMatch[1] : '';

  if (!canonicalUrl) {
    console.warn(`No canonical URL found in ${filePath}`);
    return;
  }

  const ogTags = `
    <!-- Open Graph & Twitter Card -->
    <meta property="og:title" content="${title}" />
    <meta property="og:description" content="${description}" />
    <meta property="og:type" content="website" />
    <meta property="og:url" content="${canonicalUrl}" />
    <meta property="og:image" content="https://www.convertfilebox.net/assets/icon-large.png" />
    <meta name="twitter:card" content="summary_large_image" />`;

  // Insert CSP and OG after description tag
  content = content.replace(
    /(<meta\s+name="description"\s+content="[\s\S]*?"\s*\/>)/i,
    `$1\n${csp}\n${ogTags}`,
  );

  // Also fix hreflang="en" to "en-us"
  content = content.replace(/hreflang="en"/g, 'hreflang="en-us"');

  // Insert x-default hreflang
  const enMatch = canonicalUrl.match(/https:\/\/www\.convertfilebox\.net\/en-us\/(.*)/);
  const jpMatch = canonicalUrl.match(/https:\/\/www\.convertfilebox\.net\/ja-jp\/(.*)/);

  let route = '';
  if (enMatch) route = enMatch[1];
  if (jpMatch) route = jpMatch[1];

  const xdefaultUrl = `https://www.convertfilebox.net/en-us/${route}`;
  const xdefaultTag = `\n    <link rel="alternate" hreflang="x-default" href="${xdefaultUrl}" />`;

  // Find the last alternate link to insert after
  const alternateRegex = /<link\s+rel="alternate"\s+hreflang="[^"]+"\s+href="[^"]+"\s*\/>/g;
  let match;
  let lastIndex = -1;
  while ((match = alternateRegex.exec(content)) !== null) {
    lastIndex = alternateRegex.lastIndex;
  }

  if (lastIndex !== -1 && !content.includes('hreflang="x-default"')) {
    content = content.slice(0, lastIndex) + xdefaultTag + content.slice(lastIndex);
  } else if (!content.includes('hreflang="x-default"')) {
    // If no alternate links found, append to canonical
    content = content.replace(
      /(<link\s+rel="canonical"\s+href="[^"]+"\s*\/>)/i,
      `$1${xdefaultTag}`,
    );
  }

  fs.writeFileSync(filePath, content, 'utf8');
  console.log(`Processed ${filePath}`);
}

function traverse(dir) {
  const files = fs.readdirSync(dir);
  for (const file of files) {
    const fullPath = path.join(dir, file);
    if (fs.statSync(fullPath).isDirectory()) {
      if (!fullPath.includes('en-us_broken') && !fullPath.includes('ja-jp_broken')) {
        traverse(fullPath);
      }
    } else if (fullPath.endsWith('.html')) {
      processFile(fullPath);
    }
  }
}

traverse(path.join(__dirname, '..', 'en-us'));
traverse(path.join(__dirname, '..', 'ja-jp'));

const CACHE_NAME = 'convertfilebox-v1';
const urlsToCache = [
  '/',
  '/assets/css/style.css',
  '/assets/js/ui.js',
  '/assets/js/worker-csv.js',
  '/assets/js/worker-json.js',
];

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      // use catch to prevent failure if a url doesn't exist
      return Promise.allSettled(urlsToCache.map((url) => cache.add(url)));
    }),
  );
  self.skipWaiting();
});

self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((cacheNames) => {
      return Promise.all(
        cacheNames.map((cacheName) => {
          if (cacheName !== CACHE_NAME) {
            return caches.delete(cacheName);
          }
        }),
      );
    }),
  );
  self.clients.claim();
});

self.addEventListener('fetch', (event) => {
  // Only cache GET requests
  if (event.request.method !== 'GET') {
    return;
  }

  // Exclude extension requests or api requests if necessary
  if (!event.request.url.startsWith('http')) {
    return;
  }

  event.respondWith(
    caches.match(event.request).then((response) => {
      if (response) {
        return response; // Cache hit
      }
      return fetch(event.request)
        .then((networkResponse) => {
          // Dynamic caching
          if (
            !networkResponse ||
            networkResponse.status !== 200 ||
            networkResponse.type !== 'basic'
          ) {
            return networkResponse;
          }
          const responseToCache = networkResponse.clone();
          caches.open(CACHE_NAME).then((cache) => {
            cache.put(event.request, responseToCache);
          });
          return networkResponse;
        })
        .catch(() => {
          // Offline fallback could be handled here
        });
    }),
  );
});

const { test, expect } = require('@playwright/test');

test.describe('Responsive and Premium UI (M3 & Glassmorphism)', () => {
  test('Index page has new premium responsive layout', async ({ page, isMobile }) => {
    await page.goto('/');

    // Check main container bounds
    const mainContainer = page.locator('main .container').first();
    await expect(mainContainer).toBeVisible();

    // Cards should use new components classes (from global.css .card)
    const cardElements = page.locator('.card');
    // Ensure at least some cards exist
    const count = await cardElements.count();
    expect(count).toBeGreaterThan(0);

    // Test Glassmorphism header/nav presence
    const header = page.locator('header');
    await expect(header).toHaveClass(/backdrop-blur/);

    if (isMobile) {
      // Test mobile responsive padding
      const bodyPadding = await page.evaluate(() => {
        return window.getComputedStyle(document.body).padding;
      });
      // specific mobile padding checks if needed
    }
  });

  test('Tools index has premium card UI', async ({ page }) => {
    await page.goto('/en-us/tools/');

    // Check that tool links are presented as cards
    const toolCards = page.locator('.card');
    const count = await toolCards.count();
    expect(count).toBeGreaterThan(1);

    // Ensure hovering triggers transform classes if possible
    const firstCard = toolCards.first();
    await expect(firstCard).toHaveClass(/card-hover/);
  });
});
